examples.code:
const numeros = [1, 2, 3, 4, 5];

const dobles = numeros.map(n => n * 2);
console.log(dobles); // [2, 4, 6, 8, 10]

const cuadrados = numeros.map(n => n ** 2);
console.log(cuadrados); // [1, 4, 9, 16, 25]

const productos = [
  { nombre: 'Camisa', precio: 50000 },
  { nombre: 'Pantalón', precio: 80000 },
  { nombre: 'Zapatos', precio: 120000 }
];

// Extraer solo los nombres
const nombres = productos.map(p => p.nombre);
console.log(nombres); // ['Camisa', 'Pantalón', 'Zapatos']

// Calcular precios con descuento del 10%
const conDescuento = productos.map(p => ({
  ...p,
  precio: p.precio * 0.9
}));
console.log(conDescuento[0].precio); // 45000

const frutas = ['manzana', 'banana', 'naranja'];

const enMayusculas = frutas.map(f => f.toUpperCase());
console.log(enMayusculas); // ['MANZANA', 'BANANA', 'NARANJA']

const conLongitud = frutas.map(f => ({ nombre: f, letras: f.length }));
console.log(conLongitud[0]); // { nombre: 'manzana', letras: 7 }

